patch:
--- a/shifter.v
+++ b/shifter.v
@@ -1,12 +1,12 @@
 module barrel_shifter(
   input [15:0] data,
   input [3:0] shamt,
   input dir,
   output [15:0] result
 );
   assign result = (dir == 0) ? (data << shamt) : (data >> shamt);
 endmodule

 module datapath(
   input [15:0] payload,
   input [3:0] amount,
-  output [15:0] shifted
+  output [15:0] shifted,
+  input shift_dir
 );
-  barrel_shifter bs(.data(payload), .shamt(amount), .result(shifted));
+  barrel_shifter bs(.data(payload), .shamt(amount), .dir(shift_dir), .result(shifted));
 endmodule

before_code:
module barrel_shifter(
  input [15:0] data,
  input [3:0] shamt,
  input dir,
  output [15:0] result
);
  assign result = (dir == 0) ? (data << shamt) : (data >> shamt);
endmodule

module datapath(
  input [15:0] payload,
  input [3:0] amount,
  output [15:0] shifted
);
  barrel_shifter bs(.data(payload), .shamt(amount), .result(shifted));
endmodule

after_code:
module barrel_shifter(
  input [15:0] data,
  input [3:0] shamt,
  input dir,
  output [15:0] result
);
  assign result = (dir == 0) ? (data << shamt) : (data >> shamt);
endmodule

module datapath(
  input [15:0] payload,
  input [3:0] amount,
  output [15:0] shifted,
  input shift_dir
);
  barrel_shifter bs(.data(payload), .shamt(amount), .dir(shift_dir), .result(shifted));
endmodule
